"use strict";(globalThis.webpackChunkcourse=globalThis.webpackChunkcourse||[]).push([[3861],{3158(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"courseSidebar":[{"type":"link","href":"/sisepuede/es/","label":"Bienvenida","docId":"intro","unlisted":false},{"type":"category","label":"Parte I \u2014 Fundamentos","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/sisepuede/es/foundations/what-is-sisepuede","label":"\xbfQu\xe9 es SISEPUEDE?","docId":"foundations/what-is-sisepuede","unlisted":false},{"type":"link","href":"/sisepuede/es/foundations/architecture","label":"Visi\xf3n general de la arquitectura","docId":"foundations/architecture","unlisted":false},{"type":"link","href":"/sisepuede/es/foundations/installation","label":"Instalaci\xf3n y primeros pasos","docId":"foundations/installation","unlisted":false}]},{"type":"category","label":"Parte II \u2014 Esquema de Variables","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/sisepuede/es/variable-schema/model-attributes","label":"ModelAttributes","docId":"variable-schema/model-attributes","unlisted":false},{"type":"link","href":"/sisepuede/es/variable-schema/categories-units","label":"Categor\xedas y Unidades","docId":"variable-schema/categories-units","unlisted":false}],"href":"/sisepuede/es/variable-schema/"},{"type":"category","label":"Parte III \u2014 Modelos Sectoriales","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/sisepuede/es/sectoral-models/afolu","label":"AFOLU \u2014 Agricultura, Silvicultura y Otros Usos de la Tierra","docId":"sectoral-models/afolu","unlisted":false},{"type":"link","href":"/sisepuede/es/sectoral-models/circular-economy","label":"Econom\xeda Circular \u2014 Residuos y Aguas Residuales","docId":"sectoral-models/circular-economy","unlisted":false},{"type":"link","href":"/sisepuede/es/sectoral-models/energy-consumption","label":"Consumo de Energ\xeda \u2014 Subsectores del Lado de la Demanda","docId":"sectoral-models/energy-consumption","unlisted":false},{"type":"link","href":"/sisepuede/es/sectoral-models/energy-production","label":"Producci\xf3n de Energ\xeda \u2014 LP en Julia/NeMo-Mod","docId":"sectoral-models/energy-production","unlisted":false},{"type":"link","href":"/sisepuede/es/sectoral-models/ippu","label":"IPPU \u2014 Procesos Industriales y Uso de Productos","docId":"sectoral-models/ippu","unlisted":false},{"type":"link","href":"/sisepuede/es/sectoral-models/socioeconomic","label":"Socioecon\xf3mico \u2014 Drivers a trav\xe9s de todos los sectores","docId":"sectoral-models/socioeconomic","unlisted":false}]},{"type":"category","label":"Parte IV \u2014 Transformadores y Estrategias","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/sisepuede/es/transformers/transformer-vs-transformation","label":"Transformador vs Transformaci\xf3n","docId":"transformers/transformer-vs-transformation","unlisted":false},{"type":"link","href":"/sisepuede/es/transformers/strategies","label":"Estrategias \u2014 Componiendo Transformaciones","docId":"transformers/strategies","unlisted":false}]},{"type":"category","label":"Parte V \u2014 DMDU","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/sisepuede/es/dmdu/experimental-design","label":"Dise\xf1o Experimental \u2014 LHS, Estrategias y Futuros","docId":"dmdu/experimental-design","unlisted":false}]},{"type":"category","label":"Parte VI \u2014 Tutoriales Pr\xe1cticos","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/sisepuede/es/tutorials/sector-models","label":"Tutorial 1 \u2014 Modelos Sectoriales","docId":"tutorials/sector-models","unlisted":false},{"type":"link","href":"/sisepuede/es/tutorials/model-attributes","label":"Tutorial 2 \u2014 ModelAttributes","docId":"tutorials/model-attributes","unlisted":false},{"type":"link","href":"/sisepuede/es/tutorials/transformations","label":"Tutorial 3 \u2014 Trabajando con Transformaciones","docId":"tutorials/transformations","unlisted":false},{"type":"link","href":"/sisepuede/es/tutorials/sisepuede-object","label":"Tutorial 4 \u2014 El Objeto SISEPUEDE","docId":"tutorials/sisepuede-object","unlisted":false},{"type":"link","href":"/sisepuede/es/tutorials/article-6","label":"Tutorial 5 \u2014 An\xe1lisis del Art\xedculo 6 de Par\xeds","docId":"tutorials/article-6","unlisted":false},{"type":"link","href":"/sisepuede/es/tutorials/uncertain-trajectories","label":"Tutorial 6 \u2014 Trayectorias Inciertas","docId":"tutorials/uncertain-trajectories","unlisted":false},{"type":"category","label":"rendered","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/sisepuede/es/tutorials/rendered/t1","label":"Tutorial T1: Sector Models","docId":"tutorials/rendered/t1","unlisted":false},{"type":"link","href":"/sisepuede/es/tutorials/rendered/t2","label":"Tutorial T2: Model Attributes","docId":"tutorials/rendered/t2","unlisted":false},{"type":"link","href":"/sisepuede/es/tutorials/rendered/t3","label":"Tutorial T3: Working with Transformations","docId":"tutorials/rendered/t3","unlisted":false},{"type":"link","href":"/sisepuede/es/tutorials/rendered/t4","label":"Tutorial T4: SISEPUEDE Object","docId":"tutorials/rendered/t4","unlisted":false},{"type":"link","href":"/sisepuede/es/tutorials/rendered/t5","label":"Tutorial T5: Peru Article 6 Analysis","docId":"tutorials/rendered/t5","unlisted":false},{"type":"link","href":"/sisepuede/es/tutorials/rendered/t6","label":"Tutorial T6: Uncertain Trajectories","docId":"tutorials/rendered/t6","unlisted":false}]}]}]},"docs":{"dmdu/experimental-design":{"id":"dmdu/experimental-design","title":"Dise\xf1o Experimental \u2014 LHS, Estrategias y Futuros","description":"Bienvenido a la Parte V \u2014 Toma de Decisiones bajo Incertidumbre Profunda (DMDU). Los m\xf3dulos anteriores te ense\xf1aron lo que SISEPUEDE calcula \u2014 el esquema de variables, los modelos sectoriales y los transformers que componen estrategias de pol\xedtica. Este m\xf3dulo te ense\xf1a lo que SISEPUEDE ejecuta: un dise\xf1o experimental estructurado que combina elecciones de pol\xedtica con miles de futuros plausibles, de modo que las decisiones puedan someterse a pruebas de estr\xe9s en lugar de optimizarse para un solo pron\xf3stico.","sidebar":"courseSidebar"},"foundations/architecture":{"id":"foundations/architecture","title":"Visi\xf3n general de la arquitectura","description":"SISEPUEDE es un marco h\xedbrido Python + Julia organizado en torno a un pipeline determin\xedstico de 8 fases. Python es due\xf1o del esquema, los modelos sectoriales, la orquestaci\xf3n y el I/O. Julia es due\xf1o de una tarea estrecha pero computacionalmente exigente: resolver el programa lineal del sistema energ\xe9tico v\xeda NeMo-Mod. Los dos runtimes se comunican a trav\xe9s de una base de datos SQLite temporal \u2014 sin memoria compartida, sin llamadas directas a funciones a trav\xe9s de la frontera de lenguajes.","sidebar":"courseSidebar"},"foundations/installation":{"id":"foundations/installation","title":"Instalaci\xf3n y primeros pasos","description":"SISEPUEDE corre sobre Python 3.11 y depende de un back-end de Julia para la","sidebar":"courseSidebar"},"foundations/what-is-sisepuede":{"id":"foundations/what-is-sisepuede","title":"\xbfQu\xe9 es SISEPUEDE?","description":"SISEPUEDE es un marco de modelaci\xf3n integrado en Python/Julia para explorar trayectorias de descarbonizaci\xf3n a nivel pa\xeds bajo incertidumbre profunda. En lugar de producir una \xfanica trayectoria \\"\xf3ptima\\", est\xe1 construido sobre la idea de que el futuro es genuinamente desconocido \u2014 por lo que la pregunta correcta no es qu\xe9 va a suceder sino qu\xe9 pol\xedticas siguen siendo robustas a trav\xe9s del rango m\xe1s amplio posible de futuros. Esta lecci\xf3n presenta qu\xe9 es SISEPUEDE, de d\xf3nde proviene y por qu\xe9 fue dise\xf1ado de la manera en que lo fue.","sidebar":"courseSidebar"},"intro":{"id":"intro","title":"Bienvenida","description":"Este curso te ense\xf1a a usar SISEPUEDE (SImulando SEndas sectoriales y exploraci\xf3n de incertidumbre para la DEscarbonizaci\xf3n) \u2014 un marco integrado en Python/Julia para el an\xe1lisis exploratorio de trayectorias de descarbonizaci\xf3n a nivel pa\xeds bajo incertidumbre profunda. Aprender\xe1s la arquitectura del modelo, su esquema de variables, cada modelo sectorial de emisiones, c\xf3mo se componen las transformaciones y estrategias de pol\xedtica, y c\xf3mo ejecutar experimentos DMDU completos.","sidebar":"courseSidebar"},"sectoral-models/afolu":{"id":"sectoral-models/afolu","title":"AFOLU \u2014 Agricultura, Silvicultura y Otros Usos de la Tierra","description":"Bienvenido a la Parte III. AFOLU es el m\xe1s extenso e intrincado de los cuatro sectores de emisiones de SISEPUEDE: acopla un modelo de uso del suelo de Markov en tiempo discreto con una demanda agr\xedcola y ganadera responsiva, din\xe1micas de carbono en el suelo con rezagos plurianuales, y una red de flujos biog\xe9nicos de CH\u2084 y N\u2082O. Internamente, el sector est\xe1 representado por la clase AFOLU en sisepuede/models/afolu.py, un m\xf3dulo de ~5,500 l\xedneas que orquesta seis subsectores.","sidebar":"courseSidebar"},"sectoral-models/circular-economy":{"id":"sectoral-models/circular-economy","title":"Econom\xeda Circular \u2014 Residuos y Aguas Residuales","description":"El sector de Econom\xeda Circular en SISEPUEDE es un dominio de emisiones compacto pero consecuente: captura las emisiones de metano y \xf3xido nitroso provenientes de la forma en que las sociedades disponen de aquello que ya no quieren. A pesar de representar una fracci\xf3n menor de las emisiones totales que AFOLU o Energ\xeda en la mayor\xeda de los pa\xedses, los residuos y las aguas residuales tienen un impacto desproporcionado porque el CH\u2084 tiene un GWP100 de ~27\u201330 (AR6 WG1 Cap.7, Tabla 7.SM.7) y las emisiones de los rellenos sanitarios persisten durante d\xe9cadas despu\xe9s del dep\xf3sito. El sector est\xe1 implementado en sisepuede/models/circular_economy.py como la clase CircularEconomy, y sigue las Directrices del IPCC 2006 Volumen 5 (Residuos) con el Refinamiento 2019.","sidebar":"courseSidebar"},"sectoral-models/energy-consumption":{"id":"sectoral-models/energy-consumption","title":"Consumo de Energ\xeda \u2014 Subsectores del Lado de la Demanda","description":"La clase EnergyConsumption (sisepuede/models/energy_consumption.py) es la mitad del lado de la demanda del sistema energ\xe9tico de SISEPUEDE. Mientras que EnergyProduction (M\xf3dulo 10) resuelve un programa lineal de Julia/NeMo-Mod para la mezcla de suministro de electricidad y combustibles, EnergyConsumption calcula cu\xe1nta energ\xeda \xfatil necesita cada sector, qu\xe9 combustibles la entregan, y las emisiones directas de combusti\xf3n que resultan.","sidebar":"courseSidebar"},"sectoral-models/energy-production":{"id":"sectoral-models/energy-production","title":"Producci\xf3n de Energ\xeda \u2014 LP en Julia/NeMo-Mod","description":"Cualquier otro modelo sectorial en SISEPUEDE es, en su n\xfacleo, un motor de contabilidad: multiplicar una actividad por un factor de emisi\xf3n, aplicar una refinaci\xf3n de las Directrices del IPCC 2006, sumar a trav\xe9s de categor\xedas. EnergyProduction es distinto. La generaci\xf3n el\xe9ctrica \u2014 a diferencia de los hornos de cemento, la fermentaci\xf3n ent\xe9rica o el metano de rellenos sanitarios \u2014 no es una cantidad que pueda leerse de una hoja de c\xe1lculo. Es el resultado de una decisi\xf3n de despacho tomada contra un portafolio de plantas generadoras, cada una con su propio costo de combustible, eficiencia, restricciones de rampa y factor de disponibilidad. No se puede derivar la matriz de generaci\xf3n a partir de actividad \xd7 factor; hay que resolverla.","sidebar":"courseSidebar"},"sectoral-models/ippu":{"id":"sectoral-models/ippu","title":"IPPU \u2014 Procesos Industriales y Uso de Productos","description":"El sector IPPU cubre todo lo que sale de la chimenea de una f\xe1brica o del venteo de un refrigerador que no es resultado de quemar combustible para energ\xeda. La qu\xedmica de hacer clinker libera CO\u2082 de la piedra caliza sin importar si el horno se calienta con carb\xf3n o con hidr\xf3geno; un aire acondicionado fuga HFC-134a independientemente de c\xf3mo se haya generado la electricidad que opera el compresor. SISEPUEDE contabiliza estas emisiones de proceso y de uso de producto en IPPU (sisepuede/models/ippu.py), manteni\xe9ndolas r\xedgidamente desacopladas de la contabilidad de combusti\xf3n que vive en EnergyConsumption.INEN.","sidebar":"courseSidebar"},"sectoral-models/socioeconomic":{"id":"sectoral-models/socioeconomic","title":"Socioecon\xf3mico \u2014 Drivers a trav\xe9s de todos los sectores","description":"El modelo Socioecon\xf3mico es el m\xf3dulo m\xe1s peque\xf1o de SISEPUEDE \u2014 su clase principal, Socioeconomic en sisepuede/models/socioeconomic.py, tiene bastante menos de 500 l\xedneas y emite cero gases de efecto invernadero. Y sin embargo, todos los dem\xe1s modelos del framework dependen de \xe9l. Socioeconomic es la capa de drivers: produce las trayectorias demogr\xe1ficas y macroecon\xf3micas que los cuatro sectores de emisiones convierten en demanda de alimentos, generaci\xf3n de residuos, flotas vehiculares, superficie construida y producci\xf3n industrial.","sidebar":"courseSidebar"},"transformers/strategies":{"id":"transformers/strategies","title":"Estrategias \u2014 Componiendo Transformaciones","description":"En el M\xf3dulo 13 vimos que una transformaci\xf3n es una palanca de pol\xedtica individual y parametrizada \u2014 un callable que toma un DataFrame de entrada de l\xednea base y devuelve un DataFrame modificado. Sin embargo, una trayectoria real de descarbonizaci\xf3n casi nunca es una sola palanca. Es un paquete: mejorar la productividad de cultivos y detener la deforestaci\xf3n y electrificar el transporte ligero y sustituir el calor industrial de baja temperatura por renovables. SISEPUEDE captura ese concepto de empaquetado con la clase Strategy.","sidebar":"courseSidebar"},"transformers/transformer-vs-transformation":{"id":"transformers/transformer-vs-transformation","title":"Transformador vs Transformaci\xf3n","description":"Bienvenido a la Parte IV del curso. A partir de aqu\xed, pasamos de c\xf3mo SISEPUEDE simula una l\xednea base a c\xf3mo SISEPUEDE representa intervenciones de pol\xedtica. Lo primero que debes interiorizar \u2014 y la fuente de m\xe1s confusi\xf3n que cualquier otro elemento del vocabulario de SISEPUEDE \u2014 es la diferencia entre un Transformador (Transformer) y una Transformaci\xf3n (Transformation).","sidebar":"courseSidebar"},"tutorials/article-6":{"id":"tutorials/article-6","title":"Tutorial 5 \u2014 An\xe1lisis del Art\xedculo 6 de Par\xeds","description":"El Art\xedculo 6 del Acuerdo de Par\xeds establece el marco para la implementaci\xf3n cooperativa de las NDC, permitiendo a los pa\xedses comerciar Resultados de Mitigaci\xf3n Transferidos Internacionalmente (ITMOs) y emprender proyectos conjuntos de mitigaci\xf3n. Cuantificar la adicionalidad, robustez y costo-efectividad de portafolios candidatos de ITMOs requiere un modelo capaz de comparar estrategias a trav\xe9s de muchos futuros \u2014 exactamente para lo que SISEPUEDE fue dise\xf1ado. Este tutorial recorre un caso de estudio aplicado del Art\xedculo 6, mostrando c\xf3mo estructurar el espacio de estrategias, ejecutar experimentos pareados de referencia/intervenci\xf3n e interpretar los deltas de emisiones resultantes como unidades de mitigaci\xf3n transables.","sidebar":"courseSidebar"},"tutorials/model-attributes":{"id":"tutorials/model-attributes","title":"Tutorial 2 \u2014 ModelAttributes","description":"Este tutorial lleva a la pr\xe1ctica el material sobre el esquema de variables de los M\xf3dulos 4-6. Instanciar\xe1s la clase ModelAttributes, el registro central que define cada variable de entrada y salida en SISEPUEDE, y la utilizar\xe1s para navegar por sectores, subsectores, categor\xedas y unidades. Al final deber\xe1s ser capaz de buscar cualquier variable del modelo y entender exactamente qu\xe9 representa.","sidebar":"courseSidebar"},"tutorials/rendered/t1":{"id":"tutorials/rendered/t1","title":"Tutorial T1: Sector Models","description":"1 - Sector Models","sidebar":"courseSidebar"},"tutorials/rendered/t2":{"id":"tutorials/rendered/t2","title":"Tutorial T2: Model Attributes","description":"2 - Model Attributes and Model Variables","sidebar":"courseSidebar"},"tutorials/rendered/t3":{"id":"tutorials/rendered/t3","title":"Tutorial T3: Working with Transformations","description":"3 - Working with transformations","sidebar":"courseSidebar"},"tutorials/rendered/t4":{"id":"tutorials/rendered/t4","title":"Tutorial T4: SISEPUEDE Object","description":"4 - The SISEPUEDE Object","sidebar":"courseSidebar"},"tutorials/rendered/t5":{"id":"tutorials/rendered/t5","title":"Tutorial T5: Peru Article 6 Analysis","description":"This notebook is designed to help you and other users generate simulations to support Article 6 analysis:","sidebar":"courseSidebar"},"tutorials/rendered/t6":{"id":"tutorials/rendered/t6","title":"Tutorial T6: Uncertain Trajectories","description":"2 - Uncertainty Analysis","sidebar":"courseSidebar"},"tutorials/sector-models":{"id":"tutorials/sector-models","title":"Tutorial 1 \u2014 Modelos Sectoriales","description":"Este primer tutorial pr\xe1ctico lleva la teor\xeda sectorial de los M\xf3dulos 7\u201312 a la pr\xe1ctica. Instanciar\xe1s directamente cada uno de los modelos de emisiones de SISEPUEDE, los proyectar\xe1s de forma aislada y, finalmente, ejecutar\xe1s la canalizaci\xf3n integrada completa mediante SISEPUEDEModels. Al concluir, deber\xe1s sentirte c\xf3modo alternando entre un flujo de depuraci\xf3n de un solo sector y una corrida multisectorial completa.","sidebar":"courseSidebar"},"tutorials/sisepuede-object":{"id":"tutorials/sisepuede-object","title":"Tutorial 4 \u2014 El Objeto SISEPUEDE","description":"En los Tutoriales 1\u20133 trabajaste una capa a la vez: esquemas, modelos sectoriales y transformadores. Este tutorial hace un acercamiento al nivel superior, la clase SISEPUEDE \u2014 el orquestador presentado en el M\xf3dulo 2 (Arquitectura) que conecta cada componente en una canalizaci\xf3n experimental reproducible, incluyendo el muestreo LHS y la indexaci\xf3n primary_id cubiertos en el M\xf3dulo 15 (Dise\xf1o Experimental). Al finalizar ser\xe1s capaz de lanzar una corrida completa multi-estrategia y multi-futuro con un solo objeto.","sidebar":"courseSidebar"},"tutorials/transformations":{"id":"tutorials/transformations","title":"Tutorial 3 \u2014 Trabajando con Transformaciones","description":"Este tutorial recorre la pila Transformer / Transformation / Strategy que est\xe1 en el coraz\xf3n de cada corrida de pol\xedtica en SISEPUEDE. Se construye directamente sobre los M\xf3dulos 13 y 14, donde viste c\xf3mo un DataFrame de entrada de referencia se muta en un contrafactual mediante objetos de pol\xedtica componibles y orientados a atributos.","sidebar":"courseSidebar"},"tutorials/uncertain-trajectories":{"id":"tutorials/uncertain-trajectories","title":"Tutorial 6 \u2014 Trayectorias Inciertas","description":"Este tutorial operacionaliza la maquinaria de Toma de Decisiones bajo Incertidumbre Profunda (DMDU) presentada en el M\xf3dulo 15 (Dise\xf1o Experimental). Te mover\xe1s m\xe1s all\xe1 de una sola l\xednea base determinista y aprender\xe1s c\xf3mo SISEPUEDE convierte plantillas de entrada en miles de futuros plausibles mediante Muestreo Hiperc\xfabico Latino. Al finalizar te sentir\xe1s c\xf3modo inspeccionando FutureTrajectories, manipulando objetos SamplingUnit individuales y leyendo las tablas LHS que impulsan cada corrida bajo incertidumbre.","sidebar":"courseSidebar"},"variable-schema/categories-units":{"id":"variable-schema/categories-units","title":"Categor\xedas y Unidades","description":"En el M\xf3dulo 5 viste que cada esquema de variable de SISEPUEDE contiene tokens como $CAT-AGRICULTURE$ o $UNIT-MASS$ que se expanden, en el momento de la carga, a nombres concretos de columnas. Este m\xf3dulo mira bajo el cap\xf3 de d\xf3nde provienen esos tokens \u2014 las tablas de atributos en CSV que definen las dimensiones categ\xf3ricas, los sistemas de unidades y los gases del modelo \u2014 y c\xf3mo ModelAttributes los convierte en b\xfasquedas en tiempo de ejecuci\xf3n para validaci\xf3n de categor\xedas, conversi\xf3n de unidades y agregaci\xf3n por GWP.","sidebar":"courseSidebar"},"variable-schema/model-attributes":{"id":"variable-schema/model-attributes","title":"ModelAttributes","description":"ModelAttributes es el \xfanico objeto del que dependen todos los dem\xe1s componentes de SISEPUEDE. Antes de calcular cualquier emisi\xf3n, antes de aplicar cualquier transformador y antes de enviar un LP de Julia a NeMo-Mod, ModelAttributes debe estar completamente construido. Constituye la Fase 0 del pipeline de siete fases.","sidebar":"courseSidebar"},"variable-schema/variable-schema":{"id":"variable-schema/variable-schema","title":"Esquema de Nombrado de Variables","description":"Cada columna en un DataFrame de entrada o salida de SISEPUEDE lleva un nombre que no es arbitrario \u2014 es una especificaci\xf3n legible por m\xe1quina de sector, subsector, descriptor, unidades y categor\xeda. El patr\xf3n general es {descriptor}{unitsorqualifier}{$CAT-X$}, donde $CAT-X$ es un token que el framework expande en un nombre de columna concreto por categor\xeda en el momento de instanciar el modelo. Comprender este esquema es el prerrequisito para leer tablas de atributos, escribir plantillas de entrada y depurar errores de campos no coincidentes.","sidebar":"courseSidebar"}}}}')}}]);